package br.com.portfolio.ecommerce.inventory.domain;
import br.com.portfolio.ecommerce.shared.domain.BusinessException; import java.util.*;
public class InventoryItem { private final UUID productId; private int available; public InventoryItem(UUID productId,int available){this.productId=productId;this.available=available;} public void reserve(int quantity){ if(quantity<=0) throw new BusinessException("Quantidade inválida"); if(available<quantity) throw new BusinessException("Estoque insuficiente para produto "+productId); available-=quantity;} public UUID productId(){return productId;} public int available(){return available;} }
